  latlng = text.trim();
  cy.visit(Cypress.config("baseUrl"));
  cy.get(".HomeDropDown").first().select("LatLng");
  cy.get('[data-testid="searchbar-container"]').type(latlng);
  cy.get('div.primary-btn[alt="search"]').click();
  cy.contains(".runCardHomeName", "Test-Oct30-3").should("be.visible");
});

